--- packages/ui/src/engine/pixel-characters.ts	2024-06-10 12:00:00.000000000 +0000
+++ packages/ui/src/engine/pixel-characters.ts	2024-06-10 12:00:00.000000000 +0000
@@ 3247,6 +3247,73 @@
+/**
+ * Draw a visual sound indicator near a position.
+ * Supports multiple types with animated effects.
+ * @param ctx CanvasRenderingContext2D
+ * @param x X coordinate
+ * @param y Y coordinate
+ * @param type Indicator type: 'music', 'hammer', 'quill'
+ * @param frame Animation frame count
+ */
+export function drawSoundIndicator(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  type: 'music' | 'hammer' | 'quill',
+  frame: number,
+) {
+  ctx.save();
+  ctx.lineCap = 'round';
+  ctx.lineJoin = 'round';
+  ctx.lineWidth = 2;
+  ctx.shadowColor = 'rgba(0,0,0,0.2)';
+  ctx.shadowBlur = 2;
+
+  if (type === 'music') {
+    // Draw floating musical notes with vertical bob and fade
+    const noteCount = 3;
+    for (let i = 0; i < noteCount; i++) {
+      const phase = (frame * 0.1 + i * 2) % (Math.PI * 2);
+      const offsetX = Math.sin(phase * 1.5) * 6;
+      const offsetY = -Math.abs(Math.sin(phase)) * 12 - i * 8;
+      const alpha = 0.6 + 0.4 * Math.sin(phase);
+      ctx.strokeStyle = `rgba(50, 50, 120, ${alpha.toFixed(2)})`;
+      ctx.fillStyle = `rgba(100, 100, 200, ${alpha.toFixed(2)})`;
+
+      // Draw note stem
+      ctx.beginPath();
+      ctx.moveTo(x + offsetX, y + offsetY);
+      ctx.lineTo(x + offsetX, y + offsetY - 12);
+      ctx.stroke();
+
+      // Draw note head (ellipse)
+      ctx.beginPath();
+      ctx.ellipse(x + offsetX + 3, y + offsetY - 6, 4, 6, Math.PI / 4, 0, Math.PI * 2);
+      ctx.fill();
+      ctx.stroke();
+    }
+  } else if (type === 'hammer') {
+    // Draw impact lines radiating outward with fade and scale
+    const lineCount = 5;
+    for (let i = 0; i < lineCount; i++) {
+      const angle = (i / lineCount) * Math.PI * 2 + (frame * 0.15);
+      const length = 10 + 4 * Math.sin(frame * 0.3 + i);
+      const alpha = 0.5 + 0.5 * Math.cos(frame * 0.2 + i);
+      ctx.strokeStyle = `rgba(200, 100, 50, ${alpha.toFixed(2)})`;
+      ctx.beginPath();
+      ctx.moveTo(x, y);
+      ctx.lineTo(x + Math.cos(angle) * length, y + Math.sin(angle) * length);
+      ctx.stroke();
+    }
+  } else if (type === 'quill') {
+    // Draw small motion lines near quill tip with vertical flicker
+    const flicker = Math.sin(frame * 0.3) * 2;
+    ctx.strokeStyle = 'rgba(80, 80, 80, 0.7)';
+    for (let i = 0; i < 3; i++) {
+      const offsetX = i * 4 - 4;
+      const offsetY = flicker * (i % 2 === 0 ? 1 : -1);
+      ctx.beginPath();
+      ctx.moveTo(x + offsetX, y + offsetY);
+      ctx.lineTo(x + offsetX + 3, y + offsetY - 6);
+      ctx.stroke();
+    }
+  }
+
+  ctx.restore();
+}
+
